using System;
using System.Linq;
using System.Reflection;

void PrintType(Type t) {
    Console.WriteLine($"\n=== {t.FullName} ===");
    foreach (var c in t.GetConstructors(BindingFlags.Public | BindingFlags.Instance))
        Console.WriteLine($"  ctor({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
        Console.WriteLine($"  prop {p.PropertyType.Name} {p.Name}");
    foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly).Where(m => !m.IsSpecialName))
        Console.WriteLine($"  method {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
}

var asm = Assembly.Load("Microsoft.Agents.AI");

// Check ChatClientAgentRunOptions base class
var runOpts = asm.GetType("Microsoft.Agents.AI.ChatClientAgentRunOptions");
Console.WriteLine($"ChatClientAgentRunOptions base: {runOpts?.BaseType?.FullName}");

// Check AgentRunOptions
var agentRunOpts = asm.GetExportedTypes().FirstOrDefault(t => t.Name == "AgentRunOptions");
if (agentRunOpts != null) PrintType(agentRunOpts);

// Check the ChatHistoryProvider
var chp = asm.GetExportedTypes().FirstOrDefault(t => t.Name == "ChatHistoryProvider");
// Check AgentSession
var sess = asm.GetExportedTypes().FirstOrDefault(t => t.Name == "AgentSession");

// Look at MEAI assembly for ChatOptions, AIFunction, etc
var meaiAsm = Assembly.Load("Microsoft.Extensions.AI.Abstractions");
var chatOpts = meaiAsm.GetExportedTypes().FirstOrDefault(t => t.Name == "ChatOptions");
if (chatOpts != null) {
    Console.WriteLine($"\n=== {chatOpts.FullName} ===");
    foreach (var p in chatOpts.GetProperties(BindingFlags.Public | BindingFlags.Instance))
        Console.WriteLine($"  prop {p.PropertyType.Name} {p.Name}");
}

// AIFunctionFactory
var aiFuncFactory = meaiAsm.GetExportedTypes().FirstOrDefault(t => t.Name == "AIFunctionFactory");
if (aiFuncFactory != null) {
    Console.WriteLine($"\n=== {aiFuncFactory.FullName} (static) ===");
    foreach (var m in aiFuncFactory.GetMethods(BindingFlags.Public | BindingFlags.Static).Take(10))
        Console.WriteLine($"  static {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
}
