using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

// --- Shared state for note-taking ---
var notebook = new Notebook();

// --- Define tools ---
var tools = new List<AITool>
{
    AIFunctionFactory.Create(WebSearchAsync,
        name: "web_search",
        description: "Search the web for information. Returns titles, snippets, and URLs."),

    AIFunctionFactory.Create(FetchPageAsync,
        name: "fetch_page",
        description: "Fetch the text content of a web page given its URL."),

    AIFunctionFactory.Create(notebook.AddNote,
        name: "add_note",
        description: "Save a research note with a title and content for later reference."),

    AIFunctionFactory.Create(notebook.GetNotes,
        name: "get_notes",
        description: "Retrieve all saved research notes."),
};

// --- Build the chat client with function invocation guardrails ---
var innerClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var chatClient = new ChatClientBuilder(innerClient)
    .UseFunctionInvocation(configure: fic =>
    {
        fic.MaximumIterationsPerRequest = 10;
        fic.MaximumConsecutiveErrorsPerRequest = 3;
    })
    .Build();

// --- Create the research agent ---
var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An agent that researches topics by searching the web and taking notes",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 4096,
            Tools = tools,
        },
        UseProvidedChatClientAsIs = true,
    });

// --- Interactive loop ---
Console.WriteLine("🔍 Research Agent");
Console.WriteLine("═══════════════════════════════════════");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):");
Console.Write("\n> ");

while (Console.ReadLine() is { } topic && !topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
{
    if (string.IsNullOrWhiteSpace(topic))
    {
        Console.Write("> ");
        continue;
    }

    notebook.Clear();
    Console.WriteLine($"\n📚 Researching: {topic}\n");

    var session = await agent.CreateSessionAsync(
        conversationId: Guid.NewGuid().ToString());

    var response = await agent.RunAsync(
        $"Research the following topic thoroughly and provide a comprehensive summary: {topic}",
        session);

    Console.WriteLine(response.Text);

    if (response.Usage is { } usage)
    {
        Console.WriteLine($"\n📊 Tokens — input: {usage.InputTokenCount}, output: {usage.OutputTokenCount}");
    }

    Console.WriteLine("\n═══════════════════════════════════════");
    Console.WriteLine("Enter another topic (or 'quit' to exit):");
    Console.Write("\n> ");
}

Console.WriteLine("Goodbye!");
return;

// ──────────────────────────────────────────────────────────────
// Tool implementations
// ──────────────────────────────────────────────────────────────

[Description("Search the web for information on a topic")]
static async Task<string> WebSearchAsync(
    [Description("The search query string")] string query,
    CancellationToken cancellationToken = default)
{
    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

    try
    {
        var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}"
                + "&format=json&no_html=1&skip_disambig=1";
        var json = await http.GetStringAsync(url, cancellationToken);
        using var doc = JsonDocument.Parse(json);
        var root = doc.RootElement;

        var sb = new StringBuilder();
        sb.AppendLine($"Search results for: {query}\n");

        // Abstract (main answer)
        var abstractText = root.GetProperty("AbstractText").GetString();
        var abstractSource = root.GetProperty("AbstractSource").GetString();
        var abstractUrl = root.GetProperty("AbstractURL").GetString();
        if (!string.IsNullOrWhiteSpace(abstractText))
        {
            sb.AppendLine($"## Summary from {abstractSource}");
            sb.AppendLine(abstractText);
            sb.AppendLine($"Source: {abstractUrl}\n");
        }

        // Related topics
        if (root.TryGetProperty("RelatedTopics", out var topics))
        {
            var count = 0;
            foreach (var item in topics.EnumerateArray())
            {
                if (count >= 8) break;
                var text = item.TryGetProperty("Text", out var t) ? t.GetString() : null;
                var itemUrl = item.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;
                if (!string.IsNullOrWhiteSpace(text))
                {
                    sb.AppendLine($"- {text}");
                    if (!string.IsNullOrWhiteSpace(itemUrl))
                        sb.AppendLine($"  URL: {itemUrl}");
                    count++;
                }
            }
        }

        var result = sb.ToString();
        return string.IsNullOrWhiteSpace(result.Trim())
            ? $"No results found for '{query}'. Try a different search query."
            : result;
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}. Try a different query.";
    }
}

[Description("Fetch the text content of a web page")]
static async Task<string> FetchPageAsync(
    [Description("The URL of the page to fetch")] string url,
    CancellationToken cancellationToken = default)
{
    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
    http.Timeout = TimeSpan.FromSeconds(15);

    try
    {
        var html = await http.GetStringAsync(url, cancellationToken);

        // Basic HTML-to-text: strip tags, decode entities, trim whitespace
        var text = System.Text.RegularExpressions.Regex.Replace(html, "<script[^>]*>[\\s\\S]*?</script>", " ");
        text = System.Text.RegularExpressions.Regex.Replace(text, "<style[^>]*>[\\s\\S]*?</style>", " ");
        text = System.Text.RegularExpressions.Regex.Replace(text, "<[^>]+>", " ");
        text = System.Net.WebUtility.HtmlDecode(text);
        text = System.Text.RegularExpressions.Regex.Replace(text, @"\s+", " ").Trim();

        const int maxLength = 4000;
        if (text.Length > maxLength)
            text = text[..maxLength] + "\n...[truncated]";

        return $"Content from {url}:\n\n{text}";
    }
    catch (Exception ex)
    {
        return $"Failed to fetch {url}: {ex.Message}";
    }
}

// ──────────────────────────────────────────────────────────────
// Notebook: thread-safe note storage used by the agent
// ──────────────────────────────────────────────────────────────

sealed class Notebook
{
    private readonly List<(string Title, string Content)> _notes = [];

    [Description("Save a research note with a title and content")]
    public string AddNote(
        [Description("Short descriptive title")] string title,
        [Description("The note content with facts, data, or analysis")] string content)
    {
        lock (_notes)
        {
            _notes.Add((title, content));
            return $"Note '{title}' saved. Total notes: {_notes.Count}";
        }
    }

    [Description("Retrieve all saved research notes")]
    public string GetNotes()
    {
        lock (_notes)
        {
            if (_notes.Count == 0)
                return "No notes saved yet.";

            var sb = new StringBuilder();
            for (var i = 0; i < _notes.Count; i++)
            {
                sb.AppendLine($"[{i + 1}] {_notes[i].Title}");
                sb.AppendLine(_notes[i].Content);
                sb.AppendLine("---");
            }
            return sb.ToString();
        }
    }

    public void Clear()
    {
        lock (_notes)
            _notes.Clear();
    }
}

