 // Notebook: thread-safe note storage used by the agent
 // ──────────────────────────────────────────────────────────────

 sealed class Notebook
 {
     private readonly List<(string Title, string Content)> _notes = [];

     [Description("Save a research note with a title and content")]
     public string AddNote(
         [Description("Short descriptive title")] string title,
         [Description("The note content with facts, data, or analysis")] string content)
     {
         lock (_notes)
         {
             _notes.Add((title, content));
             return $"Note '{title}' saved. Total notes: {_notes.Count}";
         }
     }

     [Description("Retrieve all saved research notes")]
     public string GetNotes()
     {
         lock (_notes)
         {
             if (_notes.Count == 0)
                 return "No notes saved yet.";

             var sb = new StringBuilder();
             for (var i = 0; i < _notes.Count; i++)
             {
                 sb.AppendLine($"[{i + 1}] {_notes[i].Title}");
                 sb.AppendLine(_notes[i].Content);
                 sb.AppendLine("---");
             }
             return sb.ToString();
         }
     }

     public void Clear()
     {
         lock (_notes)
             _notes.Clear();
     }
 }
